const SUPABASE_URL = '<OPTIMAL_SUPABASE_URL>';
const SUPABASE_KEY = '<OPTIMAL_SUPABASE_SERVICE_KEY>';
const GROQ_KEY = '<GROQ_API_KEY>';
const TOPIC = 'sofla-cre';

// Step 1: Fetch recent scraped items (last 24h)
const since = new Date(Date.now() - 86400000).toISOString();
const itemsRes = await fetch(
  `${SUPABASE_URL}/rest/v1/content_scraped_items?topic=eq.${TOPIC}&scraped_at=gte.${since}&order=scraped_at.desc&limit=50`,
  { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` } }
);
const scrapedItems = await itemsRes.json();

if (!scrapedItems.length) {
  return [{ json: { skipped: true, message: 'No SoFla CRE items in last 24h' } }];
}

// Step 2: Build AI prompt
const itemSummaries = scrapedItems.map((item, i) => {
  return `${i + 1}. [${item.source}] ${item.title || 'Untitled'}\n   ${(item.content || '').substring(0, 300)}\n   URL: ${item.source_url || 'N/A'}`;
}).join('\n\n');

const prompt = `You are a commercial real estate analyst specializing in the South Florida market (Miami-Dade, Broward, Palm Beach counties). Analyze the following ${scrapedItems.length} news items scraped from CRE publications.

Provide:
1. A 2-3 paragraph executive summary of key developments in the South Florida CRE market
2. A JSON array of 3-5 key themes (short strings like "Industrial demand rising", "Office-to-resi conversions")
3. A JSON array of 2-3 notable quotes, data points, or deal details

Focus on: deal activity (sales, leases), cap rates, vacancy trends, development pipeline, investor sentiment, and submarket dynamics (Brickell, Wynwood, Doral, Fort Lauderdale, West Palm Beach, etc.)

Format your response as JSON:
{
  "summary": "...",
  "key_themes": ["..."],
  "key_quotes": ["..."]
}

--- ITEMS ---
${itemSummaries}`;

// Step 3: Call Groq AI
const groqRes = await fetch('https://api.groq.com/openai/v1/chat/completions', {
  method: 'POST',
  headers: {
    Authorization: `Bearer ${GROQ_KEY}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [
      { role: 'system', content: 'You are a South Florida commercial real estate market analyst. Always respond with valid JSON only, no markdown fences.' },
      { role: 'user', content: prompt }
    ],
    temperature: 0.3,
    max_tokens: 2000,
  })
});

const groqData = await groqRes.json();
const choice = groqData.choices?.[0]?.message?.content || '';
const cleaned = choice.replace(/^```json?\n?/i, '').replace(/\n?```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { summary: 'AI parsing failed: ' + e.message, key_themes: [], key_quotes: [] };
}

const periodStart = scrapedItems[scrapedItems.length - 1]?.scraped_at || since;
const periodEnd = scrapedItems[0]?.scraped_at || new Date().toISOString();

// Step 4: Save insight to Supabase
const insight = {
  topic: TOPIC,
  period_start: periodStart,
  period_end: periodEnd,
  summary: parsed.summary || 'No summary generated',
  key_themes: parsed.key_themes || [],
  key_quotes: parsed.key_quotes || [],
  source_count: scrapedItems.length,
  model_used: 'groq/llama-3.3-70b-versatile',
};

const saveRes = await fetch(
  `${SUPABASE_URL}/rest/v1/content_insights`,
  {
    method: 'POST',
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      Prefer: 'return=representation',
    },
    body: JSON.stringify(insight),
  }
);

if (!saveRes.ok) {
  const errText = await saveRes.text();
  return [{ json: { error: `Save failed (${saveRes.status}): ${errText}` } }];
}

const saved = await saveRes.json();
return [{ json: { insight_id: saved[0]?.id, source_count: scrapedItems.length, topic: TOPIC, summary_preview: parsed.summary?.substring(0, 200) } }];
